CREATE TABLE events (
    id SERIAL PRIMARY KEY,
    type VARCHAR(50) NOT NULL,
    payload JSONB,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

// Fire-and-forget webhook — no ordering guarantee
    const events = [
      { seq: 1, type: 'created', ts: Date.now() },
      { seq: 2, type: 'updated', ts: Date.now() },
    ];
    // Webhooks fired concurrently — may arrive out of order
    res.end(JSON.stringify({ echo: body, events, _note: 'unordered-delivery' }));

const events = [
      { seq: 1, type: 'created', ts: Date.now() },
      { seq: 2, type: 'updated', ts: Date.now() + 1 },
    ];
    events.sort((a, b) => a.seq - b.seq);
    res.end(JSON.stringify({ echo: body, events, ordered: true }));
